  3→export interface PaywallProps {
  4→  bookSlug: string
  5→  bookTitle: string
  6→  previewChapters: number
  7→  currentChapter: number
  8→  shopifyProductId?: string
  9→  mode?: 'shopify' | 'email'
 10→  onUnlock?: () => void
 11→}
 12→
 13→export function Paywall({
 14→  bookSlug,
 15→  bookTitle,
 16→  previewChapters,
 17→  currentChapter,
 18→  shopifyProductId,
 19→  mode = 'email',
 20→  onUnlock,
 21→}: PaywallProps) {
 22→  const email = useSignal('')
 23→  const isLoading = useSignal(false)
 24→  const error = useSignal('')
 25→  const isUnlocked = useSignal(false)
 26→
 27→  // Check if already unlocked
 28→  if (typeof window !== 'undefined') {
 29→    const unlocked = localStorage.getItem(`pressy-unlocked-${bookSlug}`)
 30→    if (unlocked) {
 31→      isUnlocked.value = true
 32→    }
 33→  }
 34→
 35→  if (isUnlocked.value) {
 36→    return null
 37→  }
 38→
 39→  // Show paywall if past preview chapters
 40→  if (currentChapter <= previewChapters) {
 41→    return null
 42→  }
 43→
 44→  const handleEmailSubmit = async (e: Event) => {
 45→    e.preventDefault()
 46→
 47→    if (!email.value || !email.value.includes('@')) {
 48→      error.value = 'Please enter a valid email address'
 49→      return
 50→    }
 51→
 52→    isLoading.value = true
 53→    error.value = ''
 54→
 55→    try {
 56→      // In a real implementation, this would send to a backend
 57→      // For now, just unlock locally
 58→      await new Promise((resolve) => setTimeout(resolve, 1000))
 59→
 60→      localStorage.setItem(`pressy-unlocked-${bookSlug}`, 'email')
 61→      localStorage.setItem(`pressy-email-${bookSlug}`, email.value)
 62→
 63→      isUnlocked.value = true
 64→      onUnlock?.()
 65→    } catch (err) {
 66→      error.value = 'Something went wrong. Please try again.'
 67→    } finally {
 68→      isLoading.value = false
 69→    }
 70→  }
 71→
 72→  const handleShopifyPurchase = async () => {
 73→    if (!shopifyProductId) {
 74→      error.value = 'Purchase not available'
 75→      return
 76→    }
 77→
 78→    isLoading.value = true
 79→
 80→    try {
 81→      // This would integrate with @pressy-pub/shopify
 82→      // For now, just show that it would redirect
 83→      const { createCheckout } = await import('@pressy-pub/shopify' as string)
 84→      const checkoutUrl = await createCheckout(shopifyProductId)
 85→      window.location.href = checkoutUrl
 86→    } catch (err) {
 87→      error.value = 'Failed to create checkout. Please try again.'
 88→      isLoading.value = false
 89→    }
 90→  }
 91→
 92→  return (
 93→    <div class="pressy-paywall">
 94→      <div class="pressy-paywall-content">
 95→        <div class="pressy-paywall-icon">
 96→          <svg width="48" height="48" viewBox="0 0 24 24" fill="currentColor">
 97→            <path d="M18 8h-1V6c0-2.76-2.24-5-5-5S7 3.24 7 6v2H6c-1.1 0-2 .9-2 2v10c0 1.1.9 2 2 2h12c1.1 0 2-.9 2-2V10c0-1.1-.9-2-2-2zm-6 9c-1.1 0-2-.9-2-2s.9-2 2-2 2 .9 2 2-.9 2-2 2zm3.1-9H8.9V6c0-1.71 1.39-3.1 3.1-3.1 1.71 0 3.1 1.39 3.1 3.1v2z" />
 98→          </svg>
 99→        </div>
100→
101→        <h2 class="pressy-paywall-title">Continue Reading</h2>
102→        <p class="pressy-paywall-description">
103→          You've enjoyed the first {previewChapters} chapters of "{bookTitle}".
104→          {mode === 'shopify'
105→            ? ' Purchase the full book to continue reading.'
106→            : ' Enter your email to unlock the full book.'}
107→        </p>
108→
109→        {mode === 'email' ? (
110→          <form class="pressy-paywall-form" onSubmit={handleEmailSubmit}>
111→            <input
112→              type="email"
113→              placeholder="Enter your email"
114→              value={email.value}
115→              onInput={(e) => (email.value = (e.target as HTMLInputElement).value)}
116→              class="pressy-paywall-input"
117→              disabled={isLoading.value}
118→            />
119→            <button type="submit" class="pressy-paywall-button" disabled={isLoading.value}>
120→              {isLoading.value ? 'Unlocking...' : 'Unlock Full Book'}
121→            </button>
122→          </form>
123→        ) : (
124→          <button
125→            class="pressy-paywall-button pressy-paywall-purchase"
126→            onClick={handleShopifyPurchase}
127→            disabled={isLoading.value}
128→          >
129→            {isLoading.value ? 'Processing...' : 'Purchase Now'}
130→          </button>
131→        )}
132→
133→        {error.value && <p class="pressy-paywall-error">{error.value}</p>}
134→
135→        <p class="pressy-paywall-note">
136→          {mode === 'email'
137→            ? "We'll never share your email with anyone."
138→            : 'Secure checkout powered by Shopify.'}
139→        </p>
140→      </div>
141→
142→      <style>{`
143→        .pressy-paywall {
144→          position: fixed;
145→          inset: 0;
146→          background: rgba(0, 0, 0, 0.8);
147→          display: flex;
148→          align-items: center;
149→          justify-content: center;
150→          z-index: 1000;
151→          padding: 1.5rem;
152→        }
153→
154→        .pressy-paywall-content {
155→          background: var(--color-bg);
156→          border-radius: 1rem;
157→          padding: 2.5rem;
158→          max-width: 400px;
159→          width: 100%;
160→          text-align: center;
161→        }
162→
163→        .pressy-paywall-icon {
164→          color: var(--color-accent);
165→          margin-bottom: 1.5rem;
166→        }
167→
168→        .pressy-paywall-title {
169→          font-size: var(--font-size-xl);
170→          font-weight: 600;
171→          margin-bottom: 0.75rem;
172→          color: var(--color-heading);
173→        }
174→
175→        .pressy-paywall-description {
176→          color: var(--color-text-muted);
177→          margin-bottom: 1.5rem;
178→          line-height: 1.5;
179→        }
180→
181→        .pressy-paywall-form {
182→          display: flex;
183→          flex-direction: column;
184→          gap: 0.75rem;
185→        }
186→
187→        .pressy-paywall-input {
188→          width: 100%;
189→          padding: 0.875rem 1rem;
190→          border: 1px solid var(--color-border);
191→          border-radius: 0.5rem;
192→          font-size: var(--font-size-base);
193→          background: var(--color-bg);
194→          color: var(--color-text);
195→        }
196→
197→        .pressy-paywall-input:focus {
198→          outline: none;
199→          border-color: var(--color-accent);
200→          box-shadow: 0 0 0 3px rgba(0, 102, 204, 0.1);
201→        }
202→
203→        .pressy-paywall-button {
204→          width: 100%;
205→          padding: 0.875rem 1rem;
206→          border: none;
207→          border-radius: 0.5rem;
208→          font-size: var(--font-size-base);
209→          font-weight: 500;
210→          background: var(--color-accent);
211→          color: white;
212→          cursor: pointer;
213→          transition: opacity 0.15s;
214→        }
215→
216→        .pressy-paywall-button:hover:not(:disabled) {
217→          opacity: 0.9;
218→        }
219→
220→        .pressy-paywall-button:disabled {
221→          opacity: 0.6;
222→          cursor: not-allowed;
223→        }
224→
225→        .pressy-paywall-error {
226→          color: #dc2626;
227→          font-size: var(--font-size-sm);
228→          margin-top: 0.75rem;
229→        }
230→
231→        .pressy-paywall-note {
232→          font-size: var(--font-size-sm);
233→          color: var(--color-text-muted);
234→          margin-top: 1.5rem;
235→        }
236→      `}</style>
237→    </div>
238→  )
239→}
