  1→import { useState, useEffect } from 'preact/hooks'
  2→
  3→export interface ChapterProgressInfo {
  4→  slug: string
  5→  title: string
  6→  order: number
  7→  wordCount: number
  8→  page: number
  9→  totalPages: number
 10→}
 11→
 12→export interface BookProgressProps {
 13→  bookSlug: string
 14→  chapters: Array<{
 15→    slug: string
 16→    title: string
 17→    order: number
 18→    wordCount?: number
 19→  }>
 20→  basePath: string
 21→  loadAllProgress: () => Promise<
 22→    Array<{ chapterSlug: string; page: number; totalPages: number }>
 23→  >
 24→}
 25→
 26→export function BookProgress({
 27→  chapters,
 28→  basePath,
 29→  bookSlug,
 30→  loadAllProgress,
 31→}: BookProgressProps) {
 32→  const [progressMap, setProgressMap] = useState<
 33→    Map<string, { page: number; totalPages: number }>
 34→  >(new Map())
 35→
 36→  useEffect(() => {
 37→    loadAllProgress().then((allProgress) => {
 38→      const chapterSlugs = new Set(chapters.map((ch) => ch.slug))
 39→      const map = new Map<string, { page: number; totalPages: number }>()
 40→      for (const p of allProgress) {
 41→        if (chapterSlugs.has(p.chapterSlug)) {
 42→          map.set(p.chapterSlug, { page: p.page, totalPages: p.totalPages })
 43→        }
 44→      }
 45→      setProgressMap(map)
 46→    })
 47→  }, [chapters, loadAllProgress])
 48→
 49→  // Calculate overall book progress based on word counts
 50→  const totalWords = chapters.reduce((sum, ch) => sum + (ch.wordCount || 0), 0)
 51→  let wordsRead = 0
 52→  let chaptersCompleted = 0
 53→  let chaptersStarted = 0
 54→
 55→  for (const ch of chapters) {
 56→    const progress = progressMap.get(ch.slug)
 57→    if (!progress) continue
 58→
 59→    const chapterWords = ch.wordCount || 0
 60→    if (progress.totalPages > 0 && progress.page >= progress.totalPages - 1) {
 61→      // Chapter completed
 62→      wordsRead += chapterWords
 63→      chaptersCompleted++
 64→      chaptersStarted++
 65→    } else if (progress.page > 0 && progress.totalPages > 0) {
 66→      // Chapter in progress — estimate words read from page proportion
 67→      wordsRead += (progress.page / progress.totalPages) * chapterWords
 68→      chaptersStarted++
 69→    }
 70→  }
 71→
 72→  const overallPercent = totalWords > 0 ? (wordsRead / totalWords) * 100 : 0
 73→  const hasAnyProgress = chaptersStarted > 0
 74→
 75→  return (
 76→    <div class="pressy-book-progress-section">
 77→      {hasAnyProgress && (
 78→        <div class="pressy-overall-progress">
 79→          <div class="pressy-overall-progress-bar">
 80→            <div
 81→              class="pressy-overall-progress-fill"
 82→              style={{ width: `${overallPercent}%` }}
 83→            />
 84→          </div>
 85→          <div class="pressy-overall-progress-text">
 86→            {Math.round(overallPercent)}% complete
 87→            <span class="pressy-overall-progress-detail">
 88→              {chaptersCompleted} of {chapters.length} chapters
 89→            </span>
 90→          </div>
 91→        </div>
 92→      )}
 93→
 94→      <nav class="pressy-chapter-list">
 95→        {chapters.map((ch) => {
 96→          const progress = progressMap.get(ch.slug)
 97→          const isCompleted =
 98→            progress &&
 99→            progress.totalPages > 0 &&
100→            progress.page >= progress.totalPages - 1
101→          const isStarted = progress && progress.page > 0 && !isCompleted
102→
103→          return (
104→            <a
105→              href={`${basePath}/books/${bookSlug}/${ch.slug}`}
106→              class={`pressy-chapter-link ${isCompleted ? 'pressy-chapter--completed' : ''} ${isStarted ? 'pressy-chapter--started' : ''}`}
107→            >
108→              <span class="pressy-chapter-order">{ch.order}.</span>
109→              <span class="pressy-chapter-title">{ch.title}</span>
110→              {isCompleted && (
111→                <span class="pressy-chapter-badge pressy-chapter-badge--done">
112→                  Done
113→                </span>
114→              )}
115→              {isStarted && progress && (
116→                <span class="pressy-chapter-badge pressy-chapter-badge--reading">
117→                  p.{progress.page + 1}/{progress.totalPages}
118→                </span>
119→              )}
120→            </a>
121→          )
122→        })}
123→      </nav>
124→
125→      <style>{BOOK_PROGRESS_STYLES}</style>
126→    </div>
127→  )
128→}
