import { test, expect } from '@playwright/test'

test.describe('reading progress', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/books/flatland/preface/')
    await page.waitForSelector('.pressy-paginated-viewport')
    // Clear stored progress
    await page.evaluate(() => {
      localStorage.removeItem('pressy-last-read')
      sessionStorage.clear()
    })
  })

  test('shows a progress bar', async ({ page }) => {
    await expect(page.locator('.pressy-progress-bar')).toBeAttached()
  })

  test('progress bar updates when navigating pages', async ({ page }) => {
    const getProgressWidth = () =>
      page.locator('.pressy-progress-fill').evaluate(
        (el) => parseFloat(getComputedStyle(el).width) || 0
      )

    const initialWidth = await getProgressWidth()

    // Navigate forward several pages
    for (let i = 0; i < 3; i++) {
      await page.keyboard.press('ArrowRight')
      await page.waitForTimeout(300)
    }

    const newWidth = await getProgressWidth()
    // Progress should increase (or at least change) after moving forward
    expect(newWidth).not.toBe(initialWidth)
  })

  test('saves reading position to localStorage', async ({ page }) => {
    // Navigate forward a few pages
    for (let i = 0; i < 3; i++) {
      await page.keyboard.press('ArrowRight')
      await page.waitForTimeout(300)
    }

    // Wait for debounced save
    await page.waitForTimeout(500)

    const lastRead = await page.evaluate(() =>
      localStorage.getItem('pressy-last-read')
    )

    expect(lastRead).toBeTruthy()
    const parsed = JSON.parse(lastRead!)
    expect(parsed).toHaveProperty('chapterSlug')
    expect(parsed).toHaveProperty('page')
  })

  test('restores reading position after reload', async ({ page }) => {
    // Navigate forward several pages
    for (let i = 0; i < 5; i++) {
      await page.keyboard.press('ArrowRight')
      await page.waitForTimeout(300)
    }

    // Wait for save
    await page.waitForTimeout(500)

    // Capture the current transform position
    const positionBefore = await page.locator('.pressy-prose--paginated').evaluate(
      (el) => el.style.transform
    )

    // Reload the page
    await page.reload()
    await page.waitForSelector('.pressy-paginated-viewport')
    await page.waitForTimeout(500) // wait for position restoration

    // Position should be restored (not at page 0)
    const positionAfter = await page.locator('.pressy-prose--paginated').evaluate(
      (el) => el.style.transform
    )

    // Both should have a non-zero transform (not at the start)
    expect(positionAfter).toBe(positionBefore)
  })

  test('?page=last navigates to last read position', async ({ page }) => {
    // First, read some pages to create a saved position
    for (let i = 0; i < 5; i++) {
      await page.keyboard.press('ArrowRight')
      await page.waitForTimeout(300)
    }
    await page.waitForTimeout(500) // wait for save

    // Navigate to a chapter with ?page=last
    await page.goto('/books/flatland/preface/?page=last')
    await page.waitForSelector('.pressy-paginated-viewport')
    await page.waitForTimeout(500)

    // Should not be at the very start (transform should be non-zero)
    const transform = await page.locator('.pressy-prose--paginated').evaluate(
      (el) => el.style.transform
    )

    // If position was restored, transform should not be the initial state
    // Initial state is typically translateX(0px) or no transform
    expect(transform).toBeTruthy()
  })
})

