test('restores reading position after reload', async ({ page }) => {
  // Navigate forward several pages
  for (let i = 0; i < 5; i++) {
    await page.keyboard.press('ArrowRight')
    await page.waitForTimeout(350)
  }

  // Wait for save
  await page.waitForTimeout(500)

  const positionBefore = await getTranslateX(page)
  expect(positionBefore).toBeLessThan(0) // should be negative (scrolled right)

  // Reload the page
  await page.reload()
  await waitForReaderReady(page)
  // Extra time for position restoration (async IndexedDB read)
  await page.waitForTimeout(1000)

  const positionAfter = await getTranslateX(page)
  // Position should be restored — not at page 0
  expect(positionAfter).toBeLessThan(0)
})

